17	export function quote(input: { items: Array<{ type: string }> }): number {
18	  const itemsTotal = input.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
19	  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
20	  return ceilToWholeGold(total);
21	}
